requests.testScript:
const jsonData = pw.response.body;

pw.test("Requisição concluída com sucesso (200)", () => {
    pw.expect(pw.response.status).toBe(200);
});

pw.test("Resposta bem estruturada e texto gerado", () => {
    pw.expect(jsonData.candidates !== undefined).toBe(true);
    
    if (pw.response.status === 200 && jsonData.candidates !== undefined) {
        const texto = jsonData.candidates[0].content.parts[0].text;
        
        pw.expect(typeof texto === "string").toBe(true);
    }
});

const jsonData = pw.response.body;

pw.test("Rejeitar com erro (400 ou 403)", () => {
    const statusValido = pw.response.status === 400 || pw.response.status === 403;
    pw.expect(statusValido).toBe(true);
});

pw.test("Deve retornar objeto de erro do Google", () => {
    pw.expect(jsonData.error !== undefined).toBe(true);
    
    if (jsonData.error !== undefined) {
        pw.expect(jsonData.error.message !== undefined).toBe(true);
    }
});

const jsonData = pw.response.body;

pw.test("Retornar Status 401 Unauthorized", () => {
    pw.expect(pw.response.status).toBe(401);
});

pw.test("Resposta deve conter objeto de erro", () => {
    pw.expect(jsonData.error !== undefined).toBe(true);
    
    if (jsonData.error !== undefined) {
        pw.expect(jsonData.error.status).toBe("UNAUTHENTICATED");
    }
});

//token expirado!

const jsonData = pw.response.body;

pw.test("Conexão Autorizada (200)", () => {
    pw.expect(pw.response.status).toBe(200);
});

pw.test("Retornou a lista de eventos", () => {
    pw.expect(jsonData.items !== undefined).toBe(true);
    
    if (jsonData.items !== undefined) {
        pw.expect(Array.isArray(jsonData.items)).toBe(true);
    }
});

pw.test("Validar estrutura do primeiro evento", () => {
    if (jsonData.items !== undefined && jsonData.items.length > 0) {
        const primeiroEvento = jsonData.items[0];
        pw.expect(primeiroEvento.id !== undefined).toBe(true);
        pw.expect(primeiroEvento.status !== undefined).toBe(true);
    }
});
